import { isTooltipDataEmpty } from '../utils.js';

type OverlayTooltipTemplateProps = {
  symbolAlignment?: 'left' | 'right';
};

const XYTooltip = (
  props: {
    variant: 'shared' | 'single';
    label?: string;
  } & OverlayTooltipTemplateProps,
) => {
  const data = useTooltipData().data;
  if (isTooltipDataEmpty(data)) {
    return null;
  }

  return (
    <OverlayTooltip symbolAlignment={props.symbolAlignment}>
      <OverlayTooltip.Header header1={data.header1} label={props.label} />
      <OverlayTooltip.Series
        activeItem={0}
        variant={props.variant}
        data={data.series}
        seriesItemTemplate={(current) => {
          return (
            <OverlayTooltip.SeriesItem
              {...current}
              relativeValueUnit="%"
              actions={() => asyncSeriesActions(current)}
            />
          );
        }}
      />
      <OverlayTooltip.Action
        label="Copy all values"
        icon={<CopyIcon />}
        onSelect={() =>
          showToast({
            title: 'Copy all values',
            type: 'info',
            lifespan: 1000,
          })
        }
      />
    </OverlayTooltip>
  );
};

